const resp = $json || {};
const upstream = $('Build review prompt').item.json;
const draft_id = upstream.draft_id;
const draft_title = upstream.draft_title;
const draft_tier = upstream.draft_tier;
const existing_metadata = upstream.draft_metadata_existing || {};
const runAtIso = upstream.runAtIso;

// Extract assistant text + JSON block
const textBlocks = Array.isArray(resp.content) ? resp.content.filter(c => c && c.type === 'text').map(c => c.text || '') : [];
const combined = textBlocks.join('\n');

let parsed = null;
const fenceMatch = combined.match(/```json\s*([\s\S]*?)```/i);
if (fenceMatch) {
  try { parsed = JSON.parse(fenceMatch[1].trim()); } catch (e) { parsed = null; }
}
if (!parsed) {
  const braceMatch = combined.match(/\{[\s\S]*\}/);
  if (braceMatch) {
    try { parsed = JSON.parse(braceMatch[0]); } catch (e) { parsed = null; }
  }
}

// Safe fallback: if Claude output is unparseable, treat as revise for human review.
const action = (parsed && ['approve','revise','reject'].includes(parsed.action)) ? parsed.action : 'revise';
const reason = (parsed && typeof parsed.reason === 'string') ? parsed.reason.slice(0, 240) : 'Claude output unparseable - human review required';

const reviewAddendum = {
  editorial_review: {
    action,
    reason,
    forbidden_phrases_found: (parsed && Array.isArray(parsed.forbidden_phrases_found)) ? parsed.forbidden_phrases_found.slice(0, 20) : [],
    missing_required: (parsed && Array.isArray(parsed.missing_required)) ? parsed.missing_required.slice(0, 20) : [],
    inline_edits: (parsed && Array.isArray(parsed.inline_edits)) ? parsed.inline_edits.slice(0, 5).map(s => String(s).slice(0, 400)) : [],
    reviewed_at: new Date().toISOString(),
    run_at: runAtIso,
    model: resp.model || 'claude-opus-4-7',
    stop_reason: resp.stop_reason,
    usage: resp.usage,
    raw_text_preview: combined.slice(0, 4000)
  }
};

// Merge with existing metadata so we do not clobber other columns' siblings.
const merged_metadata = Object.assign({}, existing_metadata, reviewAddendum);

let new_status, needs_task = false, task_body = null;
if (action === 'approve') {
  new_status = 'review_passed';
} else if (action === 'revise') {
  new_status = 'revisions_requested';
  needs_task = true;
  task_body = [{
    agent_name: 'editorial',
    task_type: 'content_revision',
    status: 'queued',
    priority: 150,
    payload: {
      source_workflow: 'editorial_publish_gate',
      editorial_article_id: draft_id,
      editorial_article_title: draft_title,
      action_required: 'revise_tier2_draft',
      reason,
      inline_edits: reviewAddendum.editorial_review.inline_edits
    }
  }];
} else {
  new_status = 'rejected';
}

const patch_body = { status: new_status, metadata: merged_metadata };
if (action === 'approve') {
  patch_body.review_passed_at = new Date().toISOString();
}

return {
  json: {
    draft_id,
    draft_title,
    draft_tier,
    action,
    reason,
    new_status,
    patch_body,
    needs_task,
    task_body,
    runAtIso
  }
};
